import "./styles/fonts.css"; // Google Fonts for built-in themes
import "./styles/tokens.css"; // active theme — generated by scaffold (see THEMES.md)
import "./styles/base.css";
import "./styles/animations.css";
import "./styles/print.css"; // PDF export stylesheet (see hooks/usePdfExport.ts)

import { useCallback, useEffect } from "react";
import { AutoStartGate } from "./components/AutoStartGate";
import { AutoToggle } from "./components/AutoToggle";
import { PageNumber } from "./components/PageNumber";
import { ProgressBar } from "./components/ProgressBar";
import { Stage } from "./components/Stage";
import { SubtitleBar } from "./components/SubtitleBar";
import { TopMenu } from "./components/TopMenu";
import { useAudioPlayer } from "./hooks/useAudioPlayer";
import { useAutoMode } from "./hooks/useAutoMode";
import { isRecordingMode, usePauseControl } from "./hooks/usePauseControl";
import { usePdfExport } from "./hooks/usePdfExport";
import { usePlaybackRate } from "./hooks/usePlaybackRate";
import { notifyCursorToParent, usePlayControlBridge } from "./hooks/usePlayControlBridge";
import { useStepper } from "./hooks/useStepper";
import { useSubtitleSettings } from "./hooks/useSubtitleSettings";
import { CHAPTERS } from "./registry/chapters";

/**
 * 成品播放器的根組件。
 *
 * 這個檔案不決定單一版型的排版細節，但它決定整個 presentation 如何載入章節、字幕、音訊、自動播放與 PDF 匯出。
 * 若你在找「模板最終怎麼把各章節接起來」，這裡是主入口。
 */
/**
 * Estimate spoken duration of a Chinese narration string. Native pace
 * ≈ 4 char/s → 250ms per char. Used as Auto-mode fallback ONLY when the
 * audio file is missing / fails / the narration is empty. When audio plays
 * normally, this value is unused — auto-advance fires on `audio.ended`.
 */
function estimateMs(text: string): number {
  if (!text) return 1500;
  return Math.max(1500, text.length * 250);
}

export default function App() {
  // CHAPTERS 是 codegen 後的總章節註冊表；每個章節 Component 就是成品模板的一個實例。
  const stepper = useStepper(CHAPTERS);
  const ch = CHAPTERS[stepper.cursor.chapter]!;
  const Cmp = ch.Component;
  const stepText = ch.narrations[stepper.cursor.step] ?? "";

  const { mode, setMode, cycleMode, autoStarted, setAutoStarted } =
    useAutoMode();

  const subtitles = useSubtitleSettings();

  usePlayControlBridge({
    onFirst: () => stepper.jumpToChapter(0, 0),
    onPrev: stepper.prev,
    onNext: stepper.next,
    onLast: () => stepper.jumpToChapter(CHAPTERS.length - 1, 9999),
    onStartAuto: () => { setAutoStarted(true); setMode("auto"); },
    onSubsOn: () => subtitles.setEnabled(true),
    onSubsOff: () => subtitles.setEnabled(false),
  });

  // 通知父頁（WvpPlayShell）目前游標位置，讓翻頁按鈕 disabled 狀態正確
  useEffect(() => {
    notifyCursorToParent(stepper.globalIndex, stepper.totalGlobal);
  }, [stepper.globalIndex, stepper.totalGlobal]);
  // Pause / resume orchestration. While `paused` is true, Stage clicks
  // are no-ops AND useAudioPlayer is forced into manual mode (the hook does
  // the work — usePauseControl just flips mode via setMode).
  const pauseCtl = usePauseControl(mode, setMode);
  // `?recording=1` is a deploy-time flag: it strips TopMenu + PageNumber
  // even in manual / audio modes. Read once at module use — not reactive.
  const recording = isRecordingMode();
  // PDF export. `printing` true ⇒ render the multi-page print deck
  // instead of the live stage. `exportPdf` is the trigger TopMenu's
  // `Download PDF` button calls.
  const pdfExport = usePdfExport();
  // Playback-rate cycle (1× / 1.25× / 1.5× / 2×). Affects audio
  // playback; chapter animations follow via `var(--speed)` + `--anim-*` tokens.
  // Persisted to localStorage and overridable via `?speed=1.5` URL param.
  const playback = usePlaybackRate();

  // Audio path follows the convention: /audio/<chapter-id>/<step+1>.mp3
  // (1-indexed file names match what `extract-narrations.ts` outputs.)
  // Empty narration → no audio src, Auto mode falls back to estimate.
  const audioSrc =
    mode === "manual" || stepText === ""
      ? null
      : `${import.meta.env.BASE_URL}audio/${ch.id}/${stepper.cursor.step + 1}.mp3`;

  // Auto-advance with section-mode chapter-end stop (spec §4 D7 + §11 B2):
  // in `section` mode, when the audio at the last step of the current
  // chapter finishes, we DON'T advance — we hold there. In every other
  // mode (`auto`, `audio` — though `audio` never reaches this callback —),
  // we just advance.
  const onAutoAdvance = useCallback(() => {
    if (
      mode === "section" &&
      stepper.cursor.step === stepper.chapterTotalSteps - 1
    ) {
      return;
    }
    stepper.next();
  }, [mode, stepper]);

  useAudioPlayer({
    src: audioSrc,
    mode,
    trailMs: 200,
    estimateFallbackMs: estimateMs(stepText),
    onAutoAdvance,
    autoStarted,
    playbackRate: playback.rate,
  });

  // Trigger PDF export from TopMenu. Wrapped to drop the Promise so the
  // button's onClick contract (() => void) stays clean — fire-and-forget;
  // the hook itself handles printing-state teardown on `afterprint`.
  // Declared BEFORE the print-branch early return so the hook order is
  // stable across the manual-stage and print-deck render paths.
  const onDownloadPdf = useCallback(() => {
    void pdfExport.exportPdf();
  }, [pdfExport]);

  // ── Print branch (B5) ─────────────────────────────────────────────
  // While `pdfExport.printing` is true, mount every (chapter, step) at
  // once inside `.print-deck`. `styles/print.css` + @media print turn this
  // into a paginated A4-landscape PDF: one step per page, no chrome,
  // SubtitleBar baked into each page. The live stage / chrome are hidden
  // by CSS (body.printing) so this branch can be flipped instantly without
  // tearing down their hook state.
  if (pdfExport.printing) {
    return (
      <div className="print-deck" data-no-advance>
        {CHAPTERS.map((chapter) =>
          chapter.narrations.map((narr, stepIdx) => {
            const ChapterCmp = chapter.Component;
            return (
              <section
                key={`${chapter.id}-${stepIdx}`}
                className="scene-print"
                data-chapter-id={chapter.id}
                data-step-index={stepIdx}
              >
                <div className="print-frame">
                  <div className="scene">
                    <ChapterCmp step={stepIdx} />
                  </div>
                </div>
                <SubtitleBar text={narr} enabled={subtitles.enabled} />
              </section>
            );
          }),
        )}
      </div>
    );
  }

  // Gate Stage clicks: paused = no-op (TopMenu Play resumes); otherwise
  // advance the stepper. AutoStartGate is still mounted underneath so
  // a paused-then-auto-cycled scenario still gets the start prompt.
  const onStageAdvance = pauseCtl.paused ? () => {} : stepper.next;

  return (
    <>
      <Stage onAdvance={onStageAdvance}>
        <div key={ch.id} className="scene">
          <Cmp step={stepper.cursor.step} />
        </div>
      </Stage>
      <ProgressBar
        chapters={CHAPTERS}
        cursor={stepper.cursor}
        onJumpChapter={stepper.jumpToChapter}
      />
      <AutoToggle mode={mode} onCycle={cycleMode} />
      <SubtitleBar text={stepText} enabled={subtitles.enabled} />
      <TopMenu
        mode={mode}
        recording={recording}
        paused={pauseCtl.paused}
        playbackRate={playback.rate}
        onRestart={() => stepper.jumpToChapter(0, 0)}
        onPause={pauseCtl.pause}
        onPlay={pauseCtl.unpause}
        onAutoSection={() => setMode("section")}
        onAutoAll={() => setMode("auto")}
        onCycleSpeed={playback.cycle}
        onDownloadPdf={onDownloadPdf}
      />
      <PageNumber
        chapterIdx={stepper.cursor.chapter}
        step={stepper.cursor.step}
        mode={mode}
        recording={recording}
      />
      <AutoStartGate
        visible={(mode === "auto" || mode === "section") && !autoStarted}
        onStart={() => setAutoStarted(true)}
      />
    </>
  );
}
